class Value:
    """A scalar value with automatic differentiation support."""

    def __init__(self, data: float, _children: tuple = (), _op: str = ''):
        self.data = float(data)
        self.grad = 0.0
        self._backward = lambda: None
        self._prev = set(_children)
        self._op = _op

    def __add__(self, other):
        pass

    def __mul__(self, other):
        pass

    def __pow__(self, exp):
        pass

    def relu(self):
        pass

    def backward(self):
        """Compute gradients via reverse-mode backprop (topological sort)."""
        pass

    # Convenience methods
    def __neg__(self):  return self * -1
    def __radd__(self, other): return self + other
    def __sub__(self, other): return self + (-other)
    def __rsub__(self, other): return other + (-self)
    def __rmul__(self, other): return self * other
    def __truediv__(self, other): return self * other**-1
    def __rtruediv__(self, other): return other * self**-1
    def __repr__(self): return f'Value(data={self.data:.4f}, grad={self.grad:.4f})'
